sp_widget.client_script:
api.controller=function($scope, $filter, spUtil,spModal) {
  /* widget controller */
  var c = this;
	$scope.showingHistory=false;

	// catch view history click from Scheduled OoO widget
	$scope.$on('$oooViewHistory', function () {
		$scope.showingHistory=true;	
	});	

	$scope.showSchedule = function(){
		$scope.showingHistory=false;		
	};

	$scope.showHistory = function(){
		$scope.showingHistory=true;		
	};

	// *******************************************
	// START NEW OOO MENU OPTION
	// *******************************************
	$scope.newOOO = function(){
		spModal.open({
			message: '',
			backdrop: 'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: c.data.table,
				sys_id: -1,
				query: c.data.newFilter,
				hideRelatedLists: false,
				omitHeader: true,
				bifold: false,
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: {},
			size: 'lg',
			buttons: [''],
			footerStyle: {
				'display': 'none'
			}
		});
	};
	// *******************************************
	// END NEW OOO MENU OPTION
	// *******************************************

};

sp_widget.css:
.ooo-text{
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #757575;
}

.ooo-backbtn{
  width: 100%;
  height: 30px;
  background-color: none;
  color: black;
  border-radius: 5px;
  box-shadow: none;
}
.ooo-backbtn:hover{
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
  cursor: pointer;
}
.ooo-backbtn:focus{
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-hyperlink{
  width: 100%;
  height: 32px;
  background-color: none;
  border-radius: 5px;
  text-decoration: underline;
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #000000;
  font-weight: 400;
  line-height: 28px;
  box-shadow: none;
}

.ooo-hyperlink:hover{
  color: #0087D2;
  cursor: pointer;
}

.ooo-hyperlink:focus{
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-hyperlink:disabled {
  color: #757575;
  cursor: none;
}

